














import Vue from 'vue';
import QuizGroupApi from '@/apis/QuizGroupApi';

export default Vue.extend({
  data() {
    return {
      autoSaveTimerId: -1,
    };
  },
  computed: {
    quizGroupName: {
      get() {
        return this.$store.state.currentQuizGroup.name;
      },
      set(value) {
        this.$store.commit('updateQuizGroupName', value);
      },
    },
  },
  methods: {
    /**
     *  Update inputed name to backend database after stopped typing for more than 1 second
     */
    autoSaveQuizGroupName() {
      clearTimeout(this.autoSaveTimerId);

      this.autoSaveTimerId = setTimeout(() => {
        const { uuid, name } = this.$store.state.currentQuizGroup;
        QuizGroupApi.updateName(this.$store.state.currentWorkspace.uuid, uuid, name);
      }, 1000);
    },
  },
});
