<template>
  <div class="about">
    <input v-model="userInput" type="text">
    <br>
    <button @click="list">
      list
    </button>
    <button @click="create">
      create
    </button>
    <button @click="retrieve">
      retrieve
    </button>
    <button @click="update">
      update
    </button>
    <button @click="destroy">
      destroy
    </button>
    <div v-for="(res, index) in result" :key="index">
      {{ res }}
    </div>
  </div>
</template>

<script>
import MemberGroupApi from '@/apis/MemberGroupApi';
import { Permission, ShareMappingUpdatePayload } from '@/apis/models/ShareMappingModel';

export default {
  components: {
    // comingsoon,
  },
  data() {
    return {
      result: [],
      monitor: -1,
      workspaceId: '293973d9-7b07-4f47-a312-a23b761912c6',
      quizEventId: '0779bb5b-4c9b-43ea-9af1-a62183d20c64',
      memberGroupId: 'd1f4c644-43f4-410b-887d-14e8a540f9ce',
      userInput: '',
    };
  },
  mounted() {
    // this.startStateMonitor();
  },
  beforeDestroy() {
    clearInterval(this.monitor);
  },
  methods: {
    list() {
      this.result.push('-');
      MemberGroupApi.share.list(this.workspaceId, this.memberGroupId).then((shareMappings) => {
        shareMappings.forEach((shareMapping) => {
          this.result.push(`${shareMapping.receiver.username} ${shareMapping.permission} ${shareMapping.uuid}`);
        });
      });
    },
    create() {
      this.result.push('-');
      MemberGroupApi.share.create(this.workspaceId, this.memberGroupId, this.userInput, Permission.GENERAL_VIEWER).then((shareMapping) => {
        this.result.push(shareMapping);
      });
    },
    retrieve() {
      this.result.push('-');
      console.log('retireve');
    },
    update() {
      this.result.push('-');
      console.log('update');

      const payload = new ShareMappingUpdatePayload(Permission.EDITOR);

      MemberGroupApi.share.update(this.workspaceId, this.memberGroupId, this.userInput, payload).then((shareMapping) => {
        this.result.push(shareMapping);
      });
    },
    destroy() {
      this.result.push('-');
      console.log('destroy');

      MemberGroupApi.share.destroy(this.workspaceId, this.memberGroupId, this.userInput).then(() => {
        this.result.push(`deleted ${this.userInput}`);
      });
    },
  },
};
</script>

